// Utility functions for sensor data management

/**
 * Format sensor value for display
 * @param {number} value - The sensor value
 * @param {number} decimals - Number of decimal places
 * @returns {string} Formatted value
 */
export const formatSensorValue = (value, decimals = 2) => {
  if (value === null || value === undefined) {
    return 'N/A';
  }
  return Number(value).toFixed(decimals);
};

/**
 * Check if DeviceMotion API is supported
 * @returns {boolean} True if supported
 */
export const isDeviceMotionSupported = () => {
  return typeof window !== 'undefined' && 'DeviceMotionEvent' in window;
};

/**
 * Check if DeviceOrientation API is supported
 * @returns {boolean} True if supported
 */
export const isDeviceOrientationSupported = () => {
  return typeof window !== 'undefined' && 'DeviceOrientationEvent' in window;
};

/**
 * Check if Geolocation API is supported
 * @returns {boolean} True if supported
 */
export const isGeolocationSupported = () => {
  return typeof window !== 'undefined' && 'geolocation' in navigator;
};

/**
 * Throttle function to limit execution rate
 * @param {Function} fn - Function to throttle
 * @param {number} delay - Delay in milliseconds
 * @returns {Function} Throttled function
 */
export const throttle = (fn, delay) => {
  let lastCall = 0;
  return function (...args) {
    const now = new Date().getTime();
    if (now - lastCall < delay) {
      return;
    }
    lastCall = now;
    return fn(...args);
  };
};

/**
 * Add data point to buffer (circular buffer pattern)
 * @param {Array} buffer - Data buffer array
 * @param {Object} dataPoint - New data point to add
 * @param {number} maxSize - Maximum buffer size
 * @returns {Array} Updated buffer
 */
export const addToBuffer = (buffer, dataPoint, maxSize = 50) => {
  const newBuffer = [...buffer, dataPoint];
  if (newBuffer.length > maxSize) {
    newBuffer.shift(); // Remove oldest point
  }
  return newBuffer;
};

/**
 * Get current timestamp for data points
 * @returns {number} Current timestamp
 */
export const getTimestamp = () => {
  return Date.now();
};

/**
 * Format timestamp for display on chart
 * @param {number} timestamp - Timestamp to format
 * @param {number} startTime - Starting reference time
 * @returns {string} Formatted time string
 */
export const formatChartTime = (timestamp, startTime) => {
  const elapsed = (timestamp - startTime) / 1000; // Convert to seconds
  return elapsed.toFixed(1) + 's';
};
