import React from 'react';
import { useGeolocation } from 'react-use';
import SensorCard from './SensorCard';
import { formatSensorValue } from '../utils/sensorHelpers';

/**
 * GPS/Geolocation sensor card component
 * @returns {JSX.Element}
 */
const GPSCard = () => {
  const state = useGeolocation();

  // Check if geolocation is supported
  const supported = 'geolocation' in navigator;

  // Extract data
  const { latitude, longitude, accuracy, altitude, speed, heading } = state;
  const loading = state.loading;
  const error = state.error ? state.error.message : null;

  return (
    <SensorCard
      title="GPS / Geolocation"
      error={error}
      loading={loading}
      supported={supported}
    >
      <div className="gps-data-grid">
        <div className="gps-data-row">
          <div className="sensor-data-label">Latitude</div>
          <div className="sensor-data-value">
            {latitude !== null && latitude !== undefined
              ? formatSensorValue(latitude, 6) + '°'
              : 'N/A'}
          </div>
        </div>
        <div className="gps-data-row">
          <div className="sensor-data-label">Longitude</div>
          <div className="sensor-data-value">
            {longitude !== null && longitude !== undefined
              ? formatSensorValue(longitude, 6) + '°'
              : 'N/A'}
          </div>
        </div>
        {accuracy && (
          <div className="gps-data-row">
            <div className="sensor-data-label">Accuracy</div>
            <div className="sensor-data-value">
              ± {formatSensorValue(accuracy, 1)} m
            </div>
          </div>
        )}
        {altitude !== null && altitude !== undefined && (
          <div className="gps-data-row">
            <div className="sensor-data-label">Altitude</div>
            <div className="sensor-data-value">
              {formatSensorValue(altitude, 1)} m
            </div>
          </div>
        )}
        {speed !== null && speed !== undefined && (
          <div className="gps-data-row">
            <div className="sensor-data-label">Speed</div>
            <div className="sensor-data-value">
              {formatSensorValue(speed, 2)} m/s
            </div>
          </div>
        )}
        {heading !== null && heading !== undefined && (
          <div className="gps-data-row">
            <div className="sensor-data-label">Heading</div>
            <div className="sensor-data-value">
              {formatSensorValue(heading, 1)}°
            </div>
          </div>
        )}
      </div>
      {!loading && !error && latitude === undefined && (
        <p className="help-text" style={{ marginTop: '16px', textAlign: 'center' }}>
          Allow location access when prompted by your browser
        </p>
      )}
    </SensorCard>
  );
};

export default GPSCard;
