import React from 'react';
import AccelerometerCard from './AccelerometerCard';
import GyroscopeCard from './GyroscopeCard';
import GPSCard from './GPSCard';
import '../styles/Dashboard.css';

/**
 * Main dashboard component displaying all sensors
 * @returns {JSX.Element}
 */
const Dashboard = () => {
  // Detect if user is on a desktop browser
  const isDesktop = window.innerWidth > 1024 && !('ontouchstart' in window);

  return (
    <div className="dashboard-container">
      <div className="dashboard-header">
        <h1 className="dashboard-title">Live Sensor Dashboard</h1>
        <p className="dashboard-subtitle">
          Real-time Accelerometer, Gyroscope, and GPS Data
        </p>
      </div>

      <div className="dashboard-instructions">
        <p>
          <strong>Instructions:</strong> Allow sensor and location permissions when prompted by your browser.
        </p>
        <p>
          This dashboard displays live data from your device's sensors in real-time with interactive charts.
        </p>
      </div>

      {isDesktop && (
        <div className="dashboard-warning">
          <p>
            <strong>Note:</strong> You appear to be on a desktop browser. Accelerometer and Gyroscope
            sensors are typically only available on mobile devices.
          </p>
          <p>
            For full functionality, please access this page on a smartphone or tablet using Chrome or Safari.
          </p>
        </div>
      )}

      <div className="dashboard-grid">
        <AccelerometerCard />
        <GyroscopeCard />
        <div className="gps-card-wrapper">
          <GPSCard />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
