import React, { useEffect, useRef, useState, useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import useAccelerometer from '../hooks/useAccelerometer';
import SensorCard from './SensorCard';
import { formatSensorValue, addToBuffer, getTimestamp } from '../utils/sensorHelpers';

/**
 * Accelerometer sensor card with live chart
 * @returns {JSX.Element}
 */
const AccelerometerCard = () => {
  const { x, y, z, error, supported, needsPermission, permissionGranted, requestPermission } = useAccelerometer();
  const [dataBuffer, setDataBuffer] = useState([]);
  const startTimeRef = useRef(Date.now());

  // Update data buffer when sensor values change
  useEffect(() => {
    if (permissionGranted && supported) {
      const timestamp = getTimestamp();
      const relativeTime = ((timestamp - startTimeRef.current) / 1000).toFixed(1);

      const dataPoint = {
        time: relativeTime,
        x: Number(x.toFixed(2)),
        y: Number(y.toFixed(2)),
        z: Number(z.toFixed(2)),
      };

      setDataBuffer((prev) => addToBuffer(prev, dataPoint, 50));
    }
  }, [x, y, z, permissionGranted, supported]);

  // Memoize chart data
  const chartData = useMemo(() => dataBuffer, [dataBuffer]);

  const handlePermissionRequest = async () => {
    await requestPermission();
  };

  return (
    <SensorCard
      title="Accelerometer"
      error={error}
      loading={false}
      supported={supported}
    >
      {needsPermission && !permissionGranted && (
        <div style={{ textAlign: 'center', padding: '20px' }}>
          <p style={{ marginBottom: '16px', color: '#9e9e9e' }}>
            Permission required to access accelerometer
          </p>
          <button className="permission-button" onClick={handlePermissionRequest}>
            Enable Accelerometer
          </button>
        </div>
      )}

      {permissionGranted && (
        <>
          <div className="sensor-data-values">
            <div className="sensor-data-item">
              <div className="sensor-data-label">X-Axis</div>
              <div className="sensor-data-value x-axis">
                {formatSensorValue(x)} m/s²
              </div>
            </div>
            <div className="sensor-data-item">
              <div className="sensor-data-label">Y-Axis</div>
              <div className="sensor-data-value y-axis">
                {formatSensorValue(y)} m/s²
              </div>
            </div>
            <div className="sensor-data-item">
              <div className="sensor-data-label">Z-Axis</div>
              <div className="sensor-data-value z-axis">
                {formatSensorValue(z)} m/s²
              </div>
            </div>
          </div>

          {chartData.length > 0 && (
            <div className="chart-container">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#444" />
                  <XAxis
                    dataKey="time"
                    stroke="#9e9e9e"
                    label={{ value: 'Time (s)', position: 'insideBottom', offset: -5, fill: '#9e9e9e' }}
                  />
                  <YAxis
                    stroke="#9e9e9e"
                    label={{ value: 'Acceleration (m/s²)', angle: -90, position: 'insideLeft', fill: '#9e9e9e' }}
                  />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#1e2127', border: '1px solid #61dafb' }}
                    labelStyle={{ color: '#61dafb' }}
                  />
                  <Legend />
                  <Line
                    type="monotone"
                    dataKey="x"
                    stroke="#f44336"
                    name="X-Axis"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                  <Line
                    type="monotone"
                    dataKey="y"
                    stroke="#4caf50"
                    name="Y-Axis"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                  <Line
                    type="monotone"
                    dataKey="z"
                    stroke="#2196f3"
                    name="Z-Axis"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                </LineChart>
              </ResponsiveContainer>
            </div>
          )}
        </>
      )}
    </SensorCard>
  );
};

export default AccelerometerCard;
