import { useState, useEffect, useRef } from 'react';
import { isDeviceMotionSupported } from '../utils/sensorHelpers';

/**
 * Custom hook for accessing accelerometer data via DeviceMotionEvent
 * @returns {Object} Accelerometer data and state
 */
const useAccelerometer = () => {
  const [data, setData] = useState({ x: 0, y: 0, z: 0 });
  const [error, setError] = useState(null);
  const [supported, setSupported] = useState(false);
  const [needsPermission, setNeedsPermission] = useState(false);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const animationFrameRef = useRef(null);
  const pendingDataRef = useRef({ x: 0, y: 0, z: 0 });

  useEffect(() => {
    // Check if DeviceMotion is supported
    const isSupported = isDeviceMotionSupported();
    setSupported(isSupported);

    if (!isSupported) {
      setError('Accelerometer not supported on this device/browser');
      return;
    }

    // Check if permission is needed (iOS 13+)
    const requiresPermission =
      typeof DeviceMotionEvent !== 'undefined' &&
      typeof DeviceMotionEvent.requestPermission === 'function';
    setNeedsPermission(requiresPermission);

    // For browsers that don't require permission, start listening immediately
    if (!requiresPermission) {
      setPermissionGranted(true);
    }
  }, []);

  /**
   * Request permission (for iOS 13+)
   */
  const requestPermission = async () => {
    try {
      if (typeof DeviceMotionEvent.requestPermission === 'function') {
        const permission = await DeviceMotionEvent.requestPermission();
        if (permission === 'granted') {
          setPermissionGranted(true);
          setError(null);
          return true;
        } else {
          setError('Permission denied for accelerometer access');
          return false;
        }
      }
      return true;
    } catch (err) {
      setError('Error requesting accelerometer permission: ' + err.message);
      return false;
    }
  };

  useEffect(() => {
    if (!supported || !permissionGranted) {
      return;
    }

    const handleMotion = (event) => {
      // Cancel any pending animation frame
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }

      // Store the latest data
      const acceleration = event.accelerationIncludingGravity;
      if (acceleration) {
        pendingDataRef.current = {
          x: acceleration.x || 0,
          y: acceleration.y || 0,
          z: acceleration.z || 0,
        };

        // Schedule update on next animation frame for smooth 60fps
        animationFrameRef.current = requestAnimationFrame(() => {
          setData(pendingDataRef.current);
        });
      }
    };

    const handleError = (err) => {
      setError('Accelerometer error: ' + err.message);
    };

    try {
      window.addEventListener('devicemotion', handleMotion);
      window.addEventListener('error', handleError);
    } catch (err) {
      setError('Failed to start accelerometer: ' + err.message);
    }

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
      window.removeEventListener('devicemotion', handleMotion);
      window.removeEventListener('error', handleError);
    };
  }, [supported, permissionGranted]);

  return {
    x: data.x,
    y: data.y,
    z: data.z,
    error,
    supported,
    needsPermission,
    permissionGranted,
    requestPermission,
  };
};

export default useAccelerometer;
