import { useState, useEffect, useRef } from 'react';
import { isDeviceOrientationSupported } from '../utils/sensorHelpers';

/**
 * Custom hook for accessing gyroscope data via DeviceOrientationEvent
 * @returns {Object} Gyroscope data and state
 */
const useGyroscope = () => {
  const [data, setData] = useState({ alpha: 0, beta: 0, gamma: 0 });
  const [error, setError] = useState(null);
  const [supported, setSupported] = useState(false);
  const [needsPermission, setNeedsPermission] = useState(false);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const animationFrameRef = useRef(null);
  const pendingDataRef = useRef({ alpha: 0, beta: 0, gamma: 0 });

  useEffect(() => {
    // Check if DeviceOrientation is supported
    const isSupported = isDeviceOrientationSupported();
    setSupported(isSupported);

    if (!isSupported) {
      setError('Gyroscope not supported on this device/browser');
      return;
    }

    // Check if permission is needed (iOS 13+)
    const requiresPermission =
      typeof DeviceOrientationEvent !== 'undefined' &&
      typeof DeviceOrientationEvent.requestPermission === 'function';
    setNeedsPermission(requiresPermission);

    // For browsers that don't require permission, start listening immediately
    if (!requiresPermission) {
      setPermissionGranted(true);
    }
  }, []);

  /**
   * Request permission (for iOS 13+)
   */
  const requestPermission = async () => {
    try {
      if (typeof DeviceOrientationEvent.requestPermission === 'function') {
        const permission = await DeviceOrientationEvent.requestPermission();
        if (permission === 'granted') {
          setPermissionGranted(true);
          setError(null);
          return true;
        } else {
          setError('Permission denied for gyroscope access');
          return false;
        }
      }
      return true;
    } catch (err) {
      setError('Error requesting gyroscope permission: ' + err.message);
      return false;
    }
  };

  useEffect(() => {
    if (!supported || !permissionGranted) {
      return;
    }

    const handleOrientation = (event) => {
      // Cancel any pending animation frame
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }

      // Store the latest data
      pendingDataRef.current = {
        alpha: event.alpha || 0, // Z-axis rotation (0-360 degrees)
        beta: event.beta || 0,   // X-axis rotation (-180 to 180 degrees)
        gamma: event.gamma || 0, // Y-axis rotation (-90 to 90 degrees)
      };

      // Schedule update on next animation frame for smooth 60fps
      animationFrameRef.current = requestAnimationFrame(() => {
        setData(pendingDataRef.current);
      });
    };

    const handleError = (err) => {
      setError('Gyroscope error: ' + err.message);
    };

    try {
      window.addEventListener('deviceorientation', handleOrientation);
      window.addEventListener('error', handleError);
    } catch (err) {
      setError('Failed to start gyroscope: ' + err.message);
    }

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
      window.removeEventListener('deviceorientation', handleOrientation);
      window.removeEventListener('error', handleError);
    };
  }, [supported, permissionGranted]);

  return {
    alpha: data.alpha,
    beta: data.beta,
    gamma: data.gamma,
    error,
    supported,
    needsPermission,
    permissionGranted,
    requestPermission,
  };
};

export default useGyroscope;
