import React, { useEffect, useRef, useState, useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import useGyroscope from '../hooks/useGyroscope';
import SensorCard from './SensorCard';
import { formatSensorValue, addToBuffer, getTimestamp } from '../utils/sensorHelpers';

/**
 * Gyroscope sensor card with live chart
 * @returns {JSX.Element}
 */
const GyroscopeCard = () => {
  const { alpha, beta, gamma, error, supported, needsPermission, permissionGranted, requestPermission } = useGyroscope();
  const [dataBuffer, setDataBuffer] = useState([]);
  const startTimeRef = useRef(Date.now());

  // Update data buffer when sensor values change
  useEffect(() => {
    if (permissionGranted && supported) {
      const timestamp = getTimestamp();
      const relativeTime = ((timestamp - startTimeRef.current) / 1000).toFixed(1);

      const dataPoint = {
        time: relativeTime,
        alpha: Number(alpha.toFixed(2)),
        beta: Number(beta.toFixed(2)),
        gamma: Number(gamma.toFixed(2)),
      };

      setDataBuffer((prev) => addToBuffer(prev, dataPoint, 50));
    }
  }, [alpha, beta, gamma, permissionGranted, supported]);

  // Memoize chart data
  const chartData = useMemo(() => dataBuffer, [dataBuffer]);

  const handlePermissionRequest = async () => {
    await requestPermission();
  };

  return (
    <SensorCard
      title="Gyroscope"
      error={error}
      loading={false}
      supported={supported}
    >
      {needsPermission && !permissionGranted && (
        <div style={{ textAlign: 'center', padding: '20px' }}>
          <p style={{ marginBottom: '16px', color: '#9e9e9e' }}>
            Permission required to access gyroscope
          </p>
          <button className="permission-button" onClick={handlePermissionRequest}>
            Enable Gyroscope
          </button>
        </div>
      )}

      {permissionGranted && (
        <>
          <div className="sensor-data-values">
            <div className="sensor-data-item">
              <div className="sensor-data-label">Alpha (Z)</div>
              <div className="sensor-data-value x-axis">
                {formatSensorValue(alpha)}°
              </div>
            </div>
            <div className="sensor-data-item">
              <div className="sensor-data-label">Beta (X)</div>
              <div className="sensor-data-value y-axis">
                {formatSensorValue(beta)}°
              </div>
            </div>
            <div className="sensor-data-item">
              <div className="sensor-data-label">Gamma (Y)</div>
              <div className="sensor-data-value z-axis">
                {formatSensorValue(gamma)}°
              </div>
            </div>
          </div>

          {chartData.length > 0 && (
            <div className="chart-container">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#444" />
                  <XAxis
                    dataKey="time"
                    stroke="#9e9e9e"
                    label={{ value: 'Time (s)', position: 'insideBottom', offset: -5, fill: '#9e9e9e' }}
                  />
                  <YAxis
                    stroke="#9e9e9e"
                    label={{ value: 'Rotation (°)', angle: -90, position: 'insideLeft', fill: '#9e9e9e' }}
                  />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#1e2127', border: '1px solid #61dafb' }}
                    labelStyle={{ color: '#61dafb' }}
                  />
                  <Legend />
                  <Line
                    type="monotone"
                    dataKey="alpha"
                    stroke="#f44336"
                    name="Alpha (Z)"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                  <Line
                    type="monotone"
                    dataKey="beta"
                    stroke="#4caf50"
                    name="Beta (X)"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                  <Line
                    type="monotone"
                    dataKey="gamma"
                    stroke="#2196f3"
                    name="Gamma (Y)"
                    dot={false}
                    isAnimationActive={false}
                    strokeWidth={2}
                  />
                </LineChart>
              </ResponsiveContainer>
            </div>
          )}
        </>
      )}
    </SensorCard>
  );
};

export default GyroscopeCard;
