import React from 'react';
import '../styles/SensorCard.css';

/**
 * Reusable wrapper component for sensor displays
 * @param {Object} props - Component props
 * @param {string} props.title - Card title
 * @param {React.ReactNode} props.children - Card content
 * @param {string} props.error - Error message if any
 * @param {boolean} props.loading - Loading state
 * @param {boolean} props.supported - Whether sensor is supported
 * @returns {JSX.Element}
 */
const SensorCard = ({ title, children, error, loading, supported }) => {
  return (
    <div className="sensor-card">
      <div className="sensor-card-header">
        <h2 className="sensor-card-title">{title}</h2>
      </div>
      <div className="sensor-card-body">
        {!supported && (
          <div className="sensor-card-message not-supported">
            <p>This sensor is not supported on your device or browser.</p>
            <p className="help-text">
              Try accessing this page on a mobile device using Chrome or Safari.
            </p>
          </div>
        )}
        {loading && supported && (
          <div className="sensor-card-message loading">
            <p>Loading sensor data...</p>
          </div>
        )}
        {error && supported && (
          <div className="sensor-card-message error">
            <p>{error}</p>
          </div>
        )}
        {!loading && !error && supported && (
          <div className="sensor-card-content">
            {children}
          </div>
        )}
      </div>
    </div>
  );
};

export default SensorCard;
